extension URLRequest {
    func logRequest(userId: String?) {
        guard let url = self.url else { return }
        
        let method = self.httpMethod ?? "GET"
        let headers = self.allHTTPHeaderFields ?? [:]
        
        APILogger.logRequest(
            url: url.absoluteString,
            method: method,
            headers: headers,
            body: self.httpBody,
            userId: userId
        )
    }
}

extension URLResponse {
    func logResponse(data: Data?, userId: String?) {
        guard let httpResponse = self as? HTTPURLResponse,
              let url = self.url else { return }
        
        APILogger.logResponse(
            url: url.absoluteString,
            statusCode: httpResponse.statusCode,
            headers: httpResponse.allHeaderFields,
            data: data,
            userId: userId
        )
    }
}

